import React from 'react';
import { NetworkProvider } from './contexts/NetworkContext';

function App() {
  return (
    <NetworkProvider>
      <div style={{ backgroundColor: '#111827', minHeight: '100vh', color: 'white', padding: '2rem' }}>
        <h1 style={{ color: '#4ade80', fontSize: '2rem', marginBottom: '1rem' }}>AI-NOC Dashboard</h1>
        <p>System initialized. Connecting to Python backend...</p>
        
        {/* We will plug your Topology Map and Device List in here next! */}
        
      </div>
    </NetworkProvider>
  );
}

export default App;
